#include <stdio.h>
int main() {
    int T, N;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        int arr[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &arr[i]);
        }
        for (int i = 0; i < N; i++) {
            if (i > 0 && arr[i - 1] + arr[i] <= 0) {
                arr[i] = -arr[i];
            }
            if (i < N - 1 && arr[i] + arr[i + 1] <= 0) {
                arr[i] = -arr[i];
            }
        }
        for (int i = 0; i < N; i++) {
            printf("%d ", arr[i]);
        }
        printf("\n");
    }
    return 0;
}

