        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] arr = new int[N];
            for (int i = 0; i < N; i++) {
                arr[i] = sc.nextInt();
            }
            for (int i = 0; i < N; i++) {
                if (i > 0 && arr[i - 1] + arr[i] <= 0) {
                    arr[i] = -arr[i];
                }
                if (i < N - 1 && arr[i] + arr[i + 1] <= 0) {
                    arr[i] = -arr[i];
                }
            }
            for (int i = 0; i < N; i++) {
                System.out.print(arr[i] + " ");
            }
            System.out.println();
